INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('elementary-0c700c30-moex-00478', 'elementary-0c700c30', 'elementary-0c700c30-moex-112-34c7f7f6', 'sub-elementary-0c700c30-02', NULL, 'single_choice', '「宗教有時會被看成是一種『迷信』，但透過這樣實地走訪臺灣各地廟宇的研究，讓我們對 宗教有了不同的理解：無論是化解悲情的受難儀式、明辨是非的神判儀式，或是重啟調解機 制的告陰狀，表面上是宗教活動，其實都是在處理人們的心理問題或社會問題。」 根據上文，下列選項最符合文意的是：', '["宗教活動幫助民眾面對自己的內心", "宗教具有洞悉社會問題的神秘力量", "宗教的功能多是信眾的期待與想像", "不該以迷信看待宗教的超自然特性"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:32+00:00", "source_pdf_sha1": "956a0c9fbe15", "answer_pdf_sha1": "1a6f54ad7459", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "508", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "統計"}'::jsonb, NULL),
  ('elementary-0c700c30-moex-00479', 'elementary-0c700c30', 'elementary-0c700c30-moex-112-34c7f7f6', 'sub-elementary-0c700c30-02', NULL, 'single_choice', '〔記者新北報導〕板橋某國中校舍改建與地下停車場工程挖出長10多公尺、胸徑3公尺的 楠木類古木，判定樹齡約300多年（在地底約5千年），校方決議取部分結合公共藝術，其 餘不予保存，引發爭議。某大學地質科學系教授說：「古木價值在於歷經的歲月及意義，以 稀有性、教育性及觀賞性來看都值得完整保留。」 根據上文，下列選項何者正確？', '["校方的決議是針對教育的需求", "學者主張保留古木以見證歷史", "學者建議取稀有木段凸顯觀賞價值", "校方為推動公共藝術保存完整古木"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:32+00:00", "source_pdf_sha1": "956a0c9fbe15", "answer_pdf_sha1": "1a6f54ad7459", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "508", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "統計"}'::jsonb, NULL),
  ('elementary-0c700c30-moex-00480', 'elementary-0c700c30', 'elementary-0c700c30-moex-112-34c7f7f6', 'sub-elementary-0c700c30-02', NULL, 'single_choice', '「目前，AI 和機器人還不太可能完全取代整個產業。如果是需要同時運用廣泛技能組合的 工作，又或是需要應付難以預見的情境，比較難用機器來取代。由此看來，醫師的主要工作 在於處理資訊：吸收醫療資訊、分析資料、再提出診斷。相對之下，護理師需要有良好的運 動能力和情緒智力，才能幫病人打針、換繃帶，或是壓制住激動的病人。因此，出現智慧型 手機 AI 醫師的時間，很有可能會遠遠早於可靠的護理機器人。」 根據上文，下列選項何者最符合文意？', '["AI和機器人的發展受限，前景不被看好", "對機器人來說，看病診斷比換繃帶更難", "護理師需要比醫師具備更多的專業知識", "醫師在未來比護理師更有可能被AI取代"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:32+00:00", "source_pdf_sha1": "956a0c9fbe15", "answer_pdf_sha1": "1a6f54ad7459", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "508", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "統計"}'::jsonb, NULL),
  ('elementary-0c700c30-moex-00481', 'elementary-0c700c30', 'elementary-0c700c30-moex-112-34c7f7f6', 'sub-elementary-0c700c30-02', NULL, 'single_choice', '「無可避免，我們在文化與社會結構上注意到什麼，仰賴的是我們站在什麼位置。我們是特 定文化與社會結構裡的局內人，所以傾向於把那些位置看成理所當然；或者是局外人，一窺 不熟悉的文化或社會結構，設法要理解種種事物。人類學家有時候把這些稱為『主位觀點』 與『客位觀點』。重要的是意識到兩者都有自身的優勢與劣勢。」 根據上文，造成局外與局內認知落差的原因是什麼？', '["基於偏見無法認知主位觀點永遠優於客位", "所處位置決定了對文化與社會結構的觀點", "注意力的焦點放在彼此結構的優勢與劣勢", "客位觀點容易將所處的位置看成理所當然"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:32+00:00", "source_pdf_sha1": "956a0c9fbe15", "answer_pdf_sha1": "1a6f54ad7459", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "508", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "統計"}'::jsonb, NULL),
  ('elementary-0c700c30-moex-00482', 'elementary-0c700c30', 'elementary-0c700c30-moex-112-34c7f7f6', 'sub-elementary-0c700c30-02', NULL, 'single_choice', '「登山最高的境界之一，是見識了一切性靈的源頭，原來盡在一步一腳印的貼身覺察與自我 生命對話；在時光雕鑿而出的眾神花園中，任何人皆可尋覓到自己的精神家園與心靈故鄉， 當生命最敏感的當下，當實實在在的活著片刻，我們可以找到歸依之處。」 根據上文，下列選項何者最符合文意？', '["登山過程可敏銳的體察自我、安頓生命", "登高望遠可以提升人格境界、精神效能", "登山是自我放逐，遠離塵俗的唯一途徑", "登山的考驗可使人看淡得失，感悟生命"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:32+00:00", "source_pdf_sha1": "956a0c9fbe15", "answer_pdf_sha1": "1a6f54ad7459", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "508", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "統計"}'::jsonb, NULL),
  ('elementary-0c700c30-moex-00483', 'elementary-0c700c30', 'elementary-0c700c30-moex-112-34c7f7f6', 'sub-elementary-0c700c30-02', NULL, 'single_choice', '「要是大家都想搬入好的學區，讓孩子上好的學校，房價就會上漲。於是家長必須為賺更高 的薪資而冒風險，因為薪資與風險相關。可是房子的數量有限、學校招生名額也有限，因此 房價漲了、許多人的工作風險也升高了，送孩子進好學校的心願還是無法實現。」 根據上文，下列選項何者最接近作者觀點？', '["只要能夠成功，可以不計承擔各種風險的代價", "好學區房屋銷售市場，供需量能與房價成正比", "為滿足需求而付出心力，結果未必能盡如人意", "將學習的責任還給孩子，追求名校是捨本逐末"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:32+00:00", "source_pdf_sha1": "956a0c9fbe15", "answer_pdf_sha1": "1a6f54ad7459", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "508", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "統計"}'::jsonb, NULL),
  ('elementary-0c700c30-moex-00484', 'elementary-0c700c30', 'elementary-0c700c30-moex-112-34c7f7f6', 'sub-elementary-0c700c30-02', NULL, 'single_choice', '「腸神經元如同大腦一般會分泌許多神經傳導物質，最有名的就是血清素。腸神經元會透過 不同方法與大腦相互溝通，像是迷走神經、多巴胺、腦內啡等，因此『腸—腦軸線』就是目 前研究的重點。又因為『人體微生物相』大多位於腸道內，所以『微生物菌相—腸—腦軸線』 也是研究腸道益生菌與大腦連線的新興科學。」 根據上文，下列選項敘述正確的是：', '["腸道內微生物的分布會影響大腦狀態", "血清素是典型受微生物支配的神經傳導物質", "腸所分泌的傳導物質通過微生物向腦發出訊息", "腸—腦軸線研究有助於開發腦內未完全使用的區域"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:32+00:00", "source_pdf_sha1": "956a0c9fbe15", "answer_pdf_sha1": "1a6f54ad7459", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "508", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "統計"}'::jsonb, NULL),
  ('elementary-0c700c30-moex-00485', 'elementary-0c700c30', 'elementary-0c700c30-moex-112-34c7f7f6', 'sub-elementary-0c700c30-02', NULL, 'single_choice', '「愛爾蘭劇作家蕭伯納說：『我有一顆蘋果，你也有一顆蘋果，交換之後，我們還是各自擁 有一顆蘋果；但如果我有一個觀念，你也有一個觀念，交流之後，我們都各擁有兩個觀念。』 資訊和知識、才能與資源的分享，讓當事人的知識和觀念加倍成長，這是人際關係中非常珍 貴的互惠原則。來源不同的觀念知能和才氣資源，在互惠分享和交流碰撞中，可以因新奇組 合而產生創意。」 根據上文，下列選項何者正確？', '["交流觀念和交換蘋果的結果是一樣的", "致力拓展人脈，可以利用彼此的資源，具有加倍效應", "吸收新奇的觀點，是彼此知識互惠交流所追求的重要目標", "人的知能與才氣不同，往往可以在互惠交流過程中產生創意"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:32+00:00", "source_pdf_sha1": "956a0c9fbe15", "answer_pdf_sha1": "1a6f54ad7459", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "508", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "統計"}'::jsonb, NULL),
  ('elementary-0c700c30-moex-00486', 'elementary-0c700c30', 'elementary-0c700c30-moex-112-34c7f7f6', 'sub-elementary-0c700c30-02', NULL, 'single_choice', '張處長榮獲模範父親表揚，同仁們擬贈匾祝賀，下列選項中的題辭何者正確？', '["教澤長存", "春暉廣被", "忠孝傳家", "壽元無量 明倫教孝"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:32+00:00", "source_pdf_sha1": "956a0c9fbe15", "answer_pdf_sha1": "1a6f54ad7459", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "508", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "統計"}'::jsonb, NULL),
  ('elementary-0c700c30-moex-00487', 'elementary-0c700c30', 'elementary-0c700c30-moex-112-34c7f7f6', 'sub-elementary-0c700c30-02', NULL, 'single_choice', '下列各選項皆出自一篇有關親子關係與青少年心理學的論述，「 」內的詞語應用正確的是：', '["親子衝突帶來的負面情緒，容易造成青少年不同類型的負面情緒，「導致」不同的問題行為", "多數父母掌控生活資源，若常採用「嚴厲」的懲罰手段，可能讓孩子產生威脅感，陷入焦 慮不安", "父母親在不自覺中的情緒勒索，會讓青少年「滋養」愧疚感，引發青少年退縮、缺乏自信、 自我孤立", "青少年階段是情緒的暴風時期，如果自尊受損，在無法「調配」控制下，可能轉而用攻擊 行為宣洩情緒 當青少年長期感受到委屈、冤枉，或因為處處受到父母的「管控」，最後可能選擇壓抑自 己而萌生怨恨感"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:32+00:00", "source_pdf_sha1": "956a0c9fbe15", "answer_pdf_sha1": "1a6f54ad7459", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "508", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "統計"}'::jsonb, NULL)
